namespace sv_928ec84197c0463f8b391f7727184cdf.Services;

public sealed class Recipe
{
    public int Id { get; init; }
    public required string Title { get; init; }
    public required string Description { get; init; }
    public int PrepTimeMinutes { get; init; }
}

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new() { Id = 1, Title = "Margherita Pizza", Description = "Classic Italian pizza with fresh mozzarella and basil.", PrepTimeMinutes = 30 },
            new() { Id = 2, Title = "Spaghetti Carbonara", Description = "Creamy pasta with pancetta, egg, and pecorino cheese.", PrepTimeMinutes = 25 },
            new() { Id = 3, Title = "Tiramisu", Description = "Layered coffee-flavored dessert with mascarpone cream.", PrepTimeMinutes = 45 },
        },
        [2] = new List<Recipe>
        {
            new() { Id = 4, Title = "Sushi Rolls", Description = "Fresh fish and vegetables wrapped in seasoned rice and nori.", PrepTimeMinutes = 60 },
            new() { Id = 5, Title = "Ramen", Description = "Rich pork bone broth with wheat noodles and soft-boiled egg.", PrepTimeMinutes = 90 },
            new() { Id = 6, Title = "Tempura", Description = "Lightly battered and fried shrimp and vegetables.", PrepTimeMinutes = 35 },
        },
        [3] = new List<Recipe>
        {
            new() { Id = 7, Title = "Tacos al Pastor", Description = "Marinated pork tacos with pineapple, cilantro, and onion.", PrepTimeMinutes = 50 },
            new() { Id = 8, Title = "Guacamole", Description = "Fresh avocado dip with lime, cilantro, and jalapeño.", PrepTimeMinutes = 10 },
            new() { Id = 9, Title = "Enchiladas Verdes", Description = "Corn tortillas filled with chicken and topped with green salsa.", PrepTimeMinutes = 40 },
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_928ec84197c0463f8b391f7727184cdf.Services
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null && _isLoading)
{
    <div class="loading-placeholder">
        <p><em>Loading recipes…</em></p>
    </div>
}
else
{
    @if (_isLoading)
    {
        <div class="refreshing-indicator">
            <small><em>Refreshing…</em></small>
        </div>
    }

    @if (_recipes is not null)
    {
        <div class="recipe-list">
            @foreach (var recipe in GetSortedRecipes())
            {
                <div class="recipe-card">
                    <h3>@recipe.Title</h3>
                    <p>@recipe.Description</p>
                    <small>Prep time: @recipe.PrepTimeMinutes minutes</small>
                </div>
            }
            @if (_recipes.Count == 0)
            {
                <p>No recipes found for this cuisine.</p>
            }
        </div>
    }
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isLoading;
    private string? _error;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            // Only sort changed — no reload needed.
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request.
        await CancelPendingRequestAsync();

        _cts = new CancellationTokenSource();
        var cancellationToken = _cts.Token;

        _isLoading = true;
        _error = null;
        StateHasChanged();

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, cancellationToken);

            if (cancellationToken.IsCancellationRequested)
                return;

            _recipes = results;
            _loadedCuisineId = CuisineId;
        }
        catch (OperationCanceledException)
        {
            // Request was cancelled — nothing to do.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isLoading = false;
        }
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null)
            return Enumerable.Empty<Recipe>();

        return Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes.OrderByDescending(r => r.Id),
            "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
            _ => _recipes
        };
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

